BEGIN
EXECUTE IMMEDIATE
'DROP SEQUENCE SEQ_PLACE_NO';
EXCEPTION
WHEN OTHERS THEN
IF SQLCODE !=
-2289 THEN
RAISE;
END IF;
END;

BEGIN
EXECUTE
IMMEDIATE 'CREATE SEQUENCE SEQ_PLACE_NO START WITH 1 INCREMENT BY 1';
END;

