mapper.insert:
INSERT INTO
PLACE_TAG_MAP (
PLACE_TAG_NO, PLACE_NO, TAG_CODE, TAG_WEIGHT,
TAG_SOURCE, TAG_CONFIDENCE
) VALUES (
SEQ_PLACE_TAG_MAP_NO.NEXTVAL,
#{placeNo}, #{tagCode}, #{tagWeight},
#{tagSource}, #{tagConfidence}
)

INSERT INTO
PLACE_HOURS (
HOURS_ID, PLACE_NO, DAY_OF_WEEK, OPEN_TIME, CLOSE_TIME,
BREAK_STRAT_TIME, BREAK_END_TIME, LAST_ORDER, IS_CLOSED
) VALUES (
SEQ_HOURS_ID.NEXTVAL, #{placeNo}, #{dayOfWeek}, #{openTime},
#{closeTime},
#{breakStratTime}, #{breakEndTime}, #{lastOrder},
#{isClosed}
)

INSERT INTO PHOTO_DATA (
	PHOTO_NO, COMMENT_NO, LOG_PHOTO_URL, PHOTO_BINARY, PHOTO_MIME_TYPE, PHOTO_FILE_NAME
) VALUES (
	SEQ_PHOTO_NO.NEXTVAL, #{commentNo}, #{logPhotoUrl}, #{photoBinary,jdbcType=BLOB}, #{photoMimeType}, #{photoFileName}
)

